## `blockscic.h`

```c
/********************************************************************
 *  BlockSci C Bindings –  single‑file public header + implementation *
 *  (c) 2024‑2026  YourName / YourCompany                           *
 *  License: MIT                                                    *
 ********************************************************************/

#ifndef BLOCKSCI_C_H
#define BLOCKSCI_C_H

/* ------------------------------------------------------------------
 *  Public C API – visible to C users
 * ------------------------------------------------------------------ */

#ifdef __cplusplus
extern "C" {
#endif

/* Opaque types – the actual definitions live in the C++ implementation. */
typedef struct bsci_iter   bsci_iter_t;   /* iterator over blocks                */
typedef struct bsci_block  bsci_block_t;  /* read‑only handle for a single block   */

/* ------------------------------------------------------------------
 *  Callback type
 *
 *  The callback is invoked for every block the iterator walks.
 *
 *  Parameters
 *  ----------
 *  block      : pointer to a read‑only `bsci_block_t` that refers to the
 *               current block.  The object is only valid for the duration
 *               of the callback (i.e. it must not be stored).
 *  user_data  : opaque pointer supplied by the caller – can be NULL.
 *
 *  Return value
 *  ------------
 *  0   – continue iterating
 *  !=0 – abort the walk; the value is propagated to `bsci_iter_for_each`.
 *
 *  The callback must not throw C++ exceptions; if it does, the wrapper
 *  will abort the iteration and return an error code.
 * ------------------------------------------------------------------ */
typedef int (*bsci_block_cb)(const bsci_block_t *block, void *user_data);

/* ------------------------------------------------------------------
 *  Creation / destruction
 * ------------------------------------------------------------------ */
bsci_iter_t *bsci_iter_create(const char *blocks_dir);   /* allocate iterator */
void         bsci_iter_destroy(bsci_iter_t *it);          /* free iterator   */

/* ------------------------------------------------------------------
 *  Manual iteration (optional)
 *
 *  Returns
 *  -------
 *   0  – a block is available; `*out_block` points to a valid handle.
 *   1  – end of collection (no more blocks).
 *  <0 – error (e.g. I/O, corrupted data, internal exception).
 * ------------------------------------------------------------------ */
int bsci_iter_next(bsci_iter_t *it, const bsci_block_t **out_block);

/* ------------------------------------------------------------------
 *  High‑performance walk – the hot path
 *
 *  The function drives the iterator and calls `cb` for each block.
 *
 *  Returns
 *  -------
 *   0  – walked all blocks successfully.
 *  >0  – the callback aborted early; the value is the callback’s return.
 *  <0 – internal error (e.g. I/O, malformed block, C++ exception).
 * ------------------------------------------------------------------ */
int bsci_iter_for_each(bsci_iter_t *it,
                       bsci_block_cb   cb,
                       void           *user_data);

/* ------------------------------------------------------------------
 *  Read‑only block accessors – all are inline, no allocation.
 *
 *  The returned pointers are owned by BlockSci; they remain valid for the
 *  duration of the callback (or until the iterator is advanced).
 * ------------------------------------------------------------------ */
static inline const char *bsci_block_get_hash(const bsci_block_t *block);
static inline uint32_t    bsci_block_get_height(const bsci_block_t *block);
static inline uint64_t    bsci_block_get_timestamp(const bsci_block_t *block);
static inline uint32_t    bsci_block_get_tx_count(const bsci_block_t *block);

/* ------------------------------------------------------------------
 *  Error handling helpers – optional convenience.
 * ------------------------------------------------------------------ */
const char *bsci_strerror(int errcode);   /* human readable description */

/* ------------------------------------------------------------------
 *  End of public API
 * ------------------------------------------------------------------ */

#ifdef __cplusplus
} /* extern "C" */
#endif

/* ------------------------------------------------------------------
 *  Implementation – compiled only when this header is included from a C++
 *  source file (e.g. when building the library).  The implementation is
 *  hidden behind an `#ifdef __cplusplus` guard so that pure C translation
 *  units see only the declarations above.
 * ------------------------------------------------------------------ */
#ifdef __cplusplus

/* ------------------------------------------------------------------
 *  Include BlockSci C++ headers (replace with the real include path).
 * ------------------------------------------------------------------ */
#include <cstddef>
#include <cstdint>
#include <cstring>
#include <memory>
#include <exception>
#include <stdexcept>
#include <string>
#include <vector>

/* ------------------------------------------------------------------
 *  Mock BlockSci API – replace with the real one.
 *
 *  In the real library you would `#include "blocksci/block.hpp"` (or
 *  whatever the header is).  The wrapper below only uses a very small
 *  subset of the API that is required for the C binding.
 * ------------------------------------------------------------------ */
namespace blocksci {

struct Block {
    std::string hash;          /* hex‑encoded 256‑bit block hash                */
    uint32_t    height;        /* block height (0‑based)                        */
    uint64_t    timestamp;     /* Unix epoch seconds                            */
    uint32_t    tx_count;      /* number of transactions in the block           */
    // … many more fields in the real library …
};

class BlockIterator {
public:
    explicit BlockIterator(const std::string &blocks_dir) {
        // In the real implementation this would open the on‑disk index.
        // For illustration we generate a tiny synthetic chain.
        (void)blocks_dir;               // suppress unused‑param warning
        for (uint32_t i = 0; i < 10; ++i) {
            Block b;
            b.hash = "deadbeef" + std::to_string(i);
            b.height = i;
            b.timestamp = 1600000000 + i * 600;
            b.tx_count = (i % 5) + 1;
            chain_.push_back(std::move(b));
        }
        pos_ = 0;
    }

    // Returns true and fills `out` while a block is available.
    bool next(Block &out) {
        if (pos_ >= chain_.size())
            return false;
        out = chain_[pos_++];
        return true;
    }

    // Random‑access helpers (used by the accessor functions)
    const Block* get(size_t idx) const {
        if (idx >= chain_.size())
            return nullptr;
        return &chain_[idx];
    }

    size_t size() const { return chain_.size(); }

private:
    std::vector<Block> chain_;
    size_t pos_;
};

} // namespace blocksci

/* ------------------------------------------------------------------
 *  Private wrapper structures – definition hidden from C users.
 * ------------------------------------------------------------------ */
struct bsci_iter {
    std::unique_ptr<blocksci::BlockIterator> iter;   /* underlying iterator   */
    blocksci::Block                         cur;    /* block produced by next */
};

struct bsci_block {
    const blocksci::Block *ptr;   /* points into the iterator’s `cur` */
};

/* ------------------------------------------------------------------
 *  Helper: map C++ exceptions to a negative error code.
 * ------------------------------------------------------------------ */
static inline int bsci_catch_exception(const std::exception &e) noexcept {
    // The actual library could have a richer mapping (e.g. EINVAL, ENOENT…)
    // For now we just return -1 for any exception and store the message.
    static thread_local std::string last_msg;
    last_msg = e.what();
    (void)last_msg;   // avoid unused warning in release builds
    return -1;
}

/* ------------------------------------------------------------------
 *  Public API implementation
 * ------------------------------------------------------------------ */

bsci_iter_t *bsci_iter_create(const char *blocks_dir) {
    if (!blocks_dir) return nullptr;
    try {
        auto *wrapper = new bsci_iter;
        wrapper->iter = std::make_unique<blocksci::BlockIterator>(std::string(blocks_dir));
        return wrapper;
    } catch (const std::exception &e) {
        // In a real library you might store the message for bsci_strerror().
        (void)e;
        return nullptr;
    }
}

void bsci_iter_destroy(bsci_iter_t *it) {
    delete it;   // safe even if it is nullptr
}

/* ------------------------------------------------------------------
 *  Manual iteration – optional convenience for C callers that want
 *  explicit control.  The returned `bsci_block_t` points to the iterator’s
 *  internal `cur` field, which stays valid until the next call to
 *  `bsci_iter_next` or until the iterator is destroyed.
 * ------------------------------------------------------------------ */
int bsci_iter_next(bsci_iter_t *it, const bsci_block_t **out_block) {
    if (!it || !out_block) return -1;
    try {
        if (!it->iter->next(it->cur))
            return 1;                         // end of collection
        // Re‑use a static wrapper for the block handle – cheap and avoids
        // per‑iteration allocation.
        static thread_local bsci_block_t blk_handle;
        blk_handle.ptr = &it->cur;
        *out_block = &blk_handle;
        return 0;
    } catch (const std::exception &e) {
        return bsci_catch_exception(e);
    }
}

/* ------------------------------------------------------------------
 *  High‑performance walk – the hot path.
 *
 *  The loop is written in C++ so the compiler can inline the accessor
 *  calls and keep the callback overhead at a minimum.  No heap allocation
 *  happens inside the iteration.
 * ------------------------------------------------------------------ */
int bsci_iter_for_each(bsci_iter_t *it,
                       bsci_block_cb   cb,
                       void           *user_data) {
    if (!it || !cb) return -1;
    try {
        while (it->iter->next(it->cur)) {
            bsci_block_t blk_handle{ &it->cur };
            int rc = cb(&blk_handle, user_data);
            if (rc != 0)               // user asked to stop early
                return rc;
        }
        return 0;                     // walked all blocks
    } catch (const std::exception &e) {
        return bsci_catch_exception(e);
    }
}

/* ------------------------------------------------------------------
 *  Inline accessor implementations – placed after the function bodies
 *  so that the compiler can see the definitions when the header is
 *  compiled as C++.
 * ------------------------------------------------------------------ */
static inline const char *bsci_block_get_hash(const bsci_block_t *block) {
    return block && block->ptr ? block->ptr->hash.c_str() : nullptr;
}
static inline uint32_t bsci_block_get_height(const bsci_block_t *block) {
    return block && block->ptr ? block->ptr->height : 0;
}
static inline uint64_t bsci_block_get_timestamp(const bsci_block_t *block) {
    return block && block->ptr ? block->ptr->timestamp : 0;
}
static inline uint32_t bsci_block_get_tx_count(const bsci_block_t *block) {
    return block && block->ptr ? block->ptr->tx_count : 0;
}

/* ------------------------------------------------------------------
 *  Human readable error strings – optional helper.
 * ------------------------------------------------------------------ */
const char *bsci_strerror(int errcode) {
    switch (errcode) {
        case 0:  return "Success";
        case 1:  return "End of collection";
        case -1: return "General failure (exception thrown)";
        default: return "Unknown error code";
    }
}

/* ------------------------------------------------------------------
 *  End of implementation
 * ------------------------------------------------------------------ */

#endif /* __cplusplus */
#endif /* BLOCKSCI_C_H */
