### How a C programmer would use the binding

```c
/* --------------------------------------------------------------
 *  example.c  –  C client code
 * -------------------------------------------------------------- */
#include "blockscic.h"
#include <stdio.h>
#include <inttypes.h>

/* Callback that prints a few fields for each block. */
static int print_block(const bsci_block_t *blk, void *user) {
    (void)user;   /* unused in this example */
    const char *hash = bsci_block_get_hash(blk);
    uint32_t    height = bsci_block_get_height(blk);
    uint64_t    ts = bsci_block_get_timestamp(blk);
    uint32_t    tx = bsci_block_get_tx_count(blk);
    printf("height=%u  hash=%s  ts=%" PRIu64 "  txs=%u\n",
           height, hash ? hash : "(null)", ts, tx);
    return 0;   /* continue iterating */
}

int main(void) {
    /* Create an iterator – the path points to the BlockSci data directory. */
    bsci_iter_t *it = bsci_iter_create("/path/to/blocksci/data");
    if (!it) {
        fprintf(stderr, "Failed to create iterator: %s\n", bsci_strerror(-1));
        return 1;
    }

    /* Walk the whole chain, invoking the callback for every block. */
    int rc = bsci_iter_for_each(it, print_block, NULL);
    if (rc < 0) {
        fprintf(stderr, "Iteration error: %s\n", bsci_strerror(rc));
    } else if (rc > 0) {
        fprintf(stderr, "Callback aborted iteration with code %d\n", rc);
    }

    bsci_iter_destroy(it);
    return 0;
}
```

Compile (assuming the implementation is compiled as C++ and linked as a static/shared library):

```bash
# Build the library
g++ -std=c++17 -fPIC -c blockscic.h -o blockscic.o   # implementation compiled as C++
ar rcs libblockscic.a blockscic.o

# Build the C client
gcc -std=c11 example.c -L. -lblockscic -o example
```

The **hot path** is the loop inside `bsci_iter_for_each`; the only work done per block is:

1. Copy a pointer to the internal `Block` object (`bsci_block_t blk_handle{&it->cur};`);
2. Call the user‑supplied C function pointer;
3. Check its return value.

No heap allocation, no string copies, and the accessor functions are `static inline`, so the compiler can completely eliminate the call overhead.  This design gives C users the same ergonomic feel as Pandas/Polars (`df.apply(callback)`) while preserving the raw performance required for 800‑million‑block scans.
